let simulation;
let linkGroup = g.append("g").attr("class", "links");
let nodeGroup = g.append("g").attr("class", "nodes");

function getAllPrereqs(code, visited = new Set()) {
    if (visited.has(code)) return [];
    visited.add(code);
    const course = COURSES[code];
    if (!course) return [];

    let prereqs = [];
    if (course.prereqs.type === "all" && course.prereqs.courses) {
        prereqs = [...course.prereqs.courses];
    } else if (course.prereqs.type === "one_of" && course.prereqs.options) {
        // For OR prereqs, add the first option's courses (shortest path)
        if (course.prereqs.options.length > 0) {
            prereqs = [...course.prereqs.options[0]];
        }
    }

    let allPrereqs = [...prereqs];
    for (const p of prereqs) {
        allPrereqs = allPrereqs.concat(getAllPrereqs(p, visited));
    }
    return allPrereqs;
}

function getEdges(code) {
    const course = COURSES[code];
    if (!course) return [];
    let edges = [];

    if (course.prereqs.type === "all" && course.prereqs.courses) {
        for (const p of course.prereqs.courses) {
            edges.push({ source: p, target: code, type: "required" });
        }
    } else if (course.prereqs.type === "one_of" && course.prereqs.options) {
        for (const option of course.prereqs.options) {
            for (const p of option) {
                edges.push({ source: p, target: code, type: "one_of" });
            }
        }
    }
    return edges;
}

function addCourse(code) {
    if (graphNodes.has(code)) {
        userSelected.add(code);
        updateSidebar();
        return;
