    userSelected.add(code);
    graphNodes.add(code);

    // Recursively add all prerequisites
    const allPrereqs = getAllPrereqs(code, new Set());
    for (const p of allPrereqs) {
        graphNodes.add(p);
    }

    // Also add all OR options (not just first)
    addAllOrOptions(code, new Set());

    updateGraph();
    updateSidebar();
}

function addAllOrOptions(code, visited) {
    if (visited.has(code)) return;
    visited.add(code);

