function rebuildGraph() {
    graphNodes.clear();
    for (const code of userSelected) {
        graphNodes.add(code);
        const allPrereqs = getAllPrereqs(code, new Set());
        for (const p of allPrereqs) graphNodes.add(p);
        addAllOrOptions(code, new Set());
    }
