function updateGraph() {
    const nodes = Array.from(graphNodes).map(code => ({
        id: code,
        course: COURSES[code] || { title: code, units: "?", prereqs: { type: "none" }, external: true },
        isUserSelected: userSelected.has(code),
        isExternal: COURSES[code]?.external || !COURSES[code]
    }));

    let edges = [];
    for (const code of graphNodes) {
        const courseEdges = getEdges(code);
        for (const e of courseEdges) {
            if (graphNodes.has(e.source) && graphNodes.has(e.target)) {
                edges.push(e);
            }
        }
    }

    // Remove duplicates
    const edgeKey = e => `${e.source}->${e.target}`;
    const seen = new Set();
    edges = edges.filter(e => {
        const k = edgeKey(e);
        if (seen.has(k)) return false;
        seen.add(k);
        return true;
    });

    // Update simulation
    if (simulation) simulation.stop();

    const width = container.clientWidth;
    const height = container.clientHeight;

    simulation = d3.forceSimulation(nodes)
        .force("link", d3.forceLink(edges).id(d => d.id).distance(120).strength(0.8))
        .force("charge", d3.forceManyBody().strength(-400))
        .force("center", d3.forceCenter(width / 2, height / 2))
        .force("y", d3.forceY().strength(0.05))
        .force("collision", d3.forceCollide(40));

    // Links
    const links = linkGroup.selectAll(".link").data(edges, d => `${d.source.id || d.source}-${d.target.id || d.target}`);
