    const nodesEnter = nodesSel.enter().append("g")
        .attr("class", "node")
        .call(d3.drag()
            .on("start", dragstarted)
            .on("drag", dragged)
            .on("end", dragended));

    nodesEnter.append("circle")
        .attr("r", 18);

    nodesEnter.append("text")
        .attr("dy", -2)
        .attr("class", "code-label");

    nodesEnter.append("text")
        .attr("dy", 10)
        .attr("class", "title-label");

    const allNodes = nodesEnter.merge(nodesSel);

    allNodes.select("circle")
        .attr("fill", d => d.isUserSelected ? "#4ecdc4" : d.isExternal ? "#555" : "#f39c12")
        .attr("stroke", d => d.isUserSelected ? "#2ecc71" : d.isExternal ? "#888" : "#e67e22");

    allNodes.select(".code-label")
        .text(d => d.id.replace("MATH ", "M").replace("MKT ", "K").replace("MSE ", "E").replace("PHYS ", "P").replace("CHEM ", "C"));

    allNodes.select(".title-label")
        .text(d => {
            const t = d.course.title;
            return t.length > 18 ? t.substring(0, 16) + "…" : t;
        });

    // Tooltip
    allNodes
        .on("mouseover", (event, d) => {
            const tooltip = document.getElementById("tooltip");
            const course = d.course;
            let prereqText = "";
            if (course.prereqs.type === "all" && course.prereqs.courses?.length) {
                prereqText = `Requires ALL: ${course.prereqs.courses.join(", ")}`;
            } else if (course.prereqs.type === "one_of" && course.prereqs.options?.length) {
                prereqText = `Requires ONE OF: ${course.prereqs.options.map(o => o.join(" + ")).join(" | ")}`;
            } else {
                prereqText = "No course prerequisites";
            }
            tooltip.innerHTML = `<div class="tt-code">${d.id}</div><div class="tt-title">${course.title} (${course.units} units)</div><div class="tt-prereqs">${prereqText}</div>${d.isExternal ? '<div style="color:#888;margin-top:4px;font-size:10px;">⚠️ Not on original catalog page</div>' : ''}`;
            tooltip.style.display = "block";
            tooltip.style.left = (event.pageX - container.getBoundingClientRect().left + 15) + "px";
            tooltip.style.top = (event.pageY - container.getBoundingClientRect().top - 10) + "px";
        })
        .on("mousemove", (event) => {
            const tooltip = document.getElementById("tooltip");
            tooltip.style.left = (event.pageX - container.getBoundingClientRect().left + 15) + "px";
            tooltip.style.top = (event.pageY - container.getBoundingClientRect().top - 10) + "px";
        })
        .on("mouseout", () => {
            document.getElementById("tooltip").style.display = "none";
        })
        .on("dblclick", (event, d) => {
            if (userSelected.has(d.id)) {
                removeCourse(d.id);
            }
        });

    simulation.on("tick", () => {
        allLinks.attr("d", d => {
            const dx = d.target.x - d.source.x;
            const dy = d.target.y - d.source.y;
            return `M${d.source.x},${d.source.y}L${d.target.x},${d.target.y}`;
        });
        allNodes.attr("transform", d => `translate(${d.x},${d.y})`);
    });

    document.getElementById("selected-count").textContent = `${graphNodes.size} (${userSelected.size} selected, ${graphNodes.size - userSelected.size} auto-added)`;
}

function dragstarted(event) {
    if (!event.active) simulation.alphaTarget(0.3).restart();
    event.subject.fx = event.subject.x;

