    const idx = SEMESTER_ORDER.indexOf(sem);
    let courses = new Set();
    for (let i = 0; i < idx; i++) {
        for (const c of plan[SEMESTER_ORDER[i]]) {
            courses.add(c.code);
        }
    }
    return courses;
}

function checkPrereqWarnings(sem, code) {
    const course = COURSES[code];
    if (!course || course.prereqs.length === 0) return [];
    const priorCourses = getCoursesBeforeSemester(sem);
    return course.prereqs.filter(p => !priorCourses.has(p));
}

function findSemesterForCourse(code) {
    for (const sem of SEMESTER_ORDER) {
        if (plan[sem].some(c => c.code === code)) return SEM_NAMES[sem];
    }
    return null;
}

function renderChecklist() {
    const planned = getAllPlannedCodes();

    // 1. Core: 5800, 5401, 5680
    const clCore = document.getElementById("cl-core");
    let coreCount = 0;
    let coreHtml = `<h4>Core Courses (3 required) <span class="progress"></span></h4>`;
    for (const code of REQ_CORE) {
        const done = planned.has(code);
        if (done) coreCount++;
        const sem = findSemesterForCourse(code);
        coreHtml += `<div class="check-item ${done ? "done" : "pending"}">
            <span class="check-icon ${done ? "done" : "pending"}">${done ? "&#10003;" : "&#9675;"}</span>
            MATH ${code} — ${COURSES[code]?.name || "?"}
            ${sem ? `<span class="check-sem">${sem}</span>` : ""}
        </div>`;
    }
    coreHtml = coreHtml.replace('<span class="progress"></span>', `<span class="progress">${coreCount}/3</span>`);
    clCore.innerHTML = coreHtml;

    // 2. Core 2: 2 from 5690, 5700, 5740, 5021
    const clCore2 = document.getElementById("cl-core2");
    let core2Count = 0;
    let core2Html = `<h4>Core Electives (2 of 4 required) <span class="progress"></span></h4>`;
    for (const code of REQ_CORE2_OPTIONS) {
        const done = planned.has(code);
        if (done) core2Count++;
        const sem = findSemesterForCourse(code);
        core2Html += `<div class="check-item ${done ? "done" : "pending"}">
            <span class="check-icon ${done ? "done" : "pending"}">${done ? "&#10003;" : "&#9675;"}</span>
            MATH ${code} — ${COURSES[code]?.name || "?"}
            ${sem ? `<span class="check-sem">${sem}</span>` : ""}
        </div>`;
    }
    core2Html = core2Html.replace('<span class="progress"></span>', `<span class="progress">${Math.min(core2Count, REQ_CORE2_NEEDED)}/${REQ_CORE2_NEEDED}</span>`);
    clCore2.innerHTML = core2Html;

    // 3. Required: 4600, 4570, 4550
    const clReq = document.getElementById("cl-required");
    let reqCount = 0;
    let reqHtml = `<h4>Required Courses (all 3) <span class="progress"></span></h4>`;
    for (const code of REQ_REQUIRED) {
        const done = planned.has(code);
        if (done) reqCount++;
        const sem = findSemesterForCourse(code);
        reqHtml += `<div class="check-item ${done ? "done" : "pending"}">
            <span class="check-icon ${done ? "done" : "pending"}">${done ? "&#10003;" : "&#9675;"}</span>
            MATH ${code} — ${COURSES[code]?.name || "?"}
            ${sem ? `<span class="check-sem">${sem}</span>` : ""}
        </div>`;
    }
    reqHtml = reqHtml.replace('<span class="progress"></span>', `<span class="progress">${reqCount}/3</span>`);
    clReq.innerHTML = reqHtml;

    // 4. Electives: 4 from pool, at least 1 must be 5000+
    // 4550, 4570, 4650 also count as electives
    const clElec = document.getElementById("cl-electives");
    const elecTaken = [];
    for (const code of REQ_ELECTIVE_POOL) {
        if (planned.has(code)) elecTaken.push(code);
    }
    const elec5k = elecTaken.filter(c => parseInt(c) >= 5000);
    const elecCount = elecTaken.length;
    const has5kElective = elec5k.length >= 1;

    let elecHtml = `<h4>Electives (4 required, 1+ must be 5000+) <span class="progress"></span></h4>`;
    for (const code of elecTaken.slice(0, 6)) {
        const sem = findSemesterForCourse(code);
        elecHtml += `<div class="check-item done">
            <span class="check-icon done">&#10003;</span>
            MATH ${code} — ${COURSES[code]?.name || "?"}
            ${sem ? `<span class="check-sem">${sem}</span>` : ""}
        </div>`;
    }
    if (elecTaken.length > 6) {
        elecHtml += `<div class="check-item done" style="color:#636e72;">+ ${elecTaken.length - 6} more</div>`;
    }
    const remaining = REQ_ELECTIVES_NEEDED - elecCount;
    if (remaining > 0) {
        elecHtml += `<div class="check-item pending"><span class="check-icon pending">&#9675;</span> ${remaining} more elective${remaining > 1 ? "s" : ""} needed</div>`;
    }
    if (!has5kElective && elecCount > 0) {
        elecHtml += `<div class="check-item pending" style="color:#e17055;"><span class="check-icon pending">&#9675;</span> Need at least 1 elective at 5000+ level</div>`;
    } else if (has5kElective) {
        elecHtml += `<div class="check-item done"><span class="check-icon done">&#10003;</span> 5000+ elective requirement met (${elec5k.map(c => c).join(", ")})</div>`;
    }
    elecHtml = elecHtml.replace('<span class="progress"></span>', `<span class="progress">${Math.min(elecCount, REQ_ELECTIVES_NEEDED)}/${REQ_ELECTIVES_NEEDED}</span>`);
    clElec.innerHTML = elecHtml;

    // Overall status
    const allMet = coreCount >= 3 && core2Count >= REQ_CORE2_NEEDED && reqCount >= 3 && elecCount >= REQ_ELECTIVES_NEEDED && has5kElective;
    const status = document.getElementById("checklist-status");
    if (allMet) {
        status.className = "checklist-status complete";
        status.textContent = "All degree requirements met!";
    } else {
        const missing = [];
        if (coreCount < 3) missing.push(`${3 - coreCount} core`);
        if (core2Count < REQ_CORE2_NEEDED) missing.push(`${REQ_CORE2_NEEDED - core2Count} core elective`);
        if (reqCount < 3) missing.push(`${3 - reqCount} required`);
        if (elecCount < REQ_ELECTIVES_NEEDED) missing.push(`${REQ_ELECTIVES_NEEDED - elecCount} elective`);
        if (elecCount >= REQ_ELECTIVES_NEEDED && !has5kElective) missing.push("1 elective must be 5000+");
        status.className = "checklist-status incomplete";
        status.textContent = `Still need: ${missing.join(", ")}`;
    }
}

function render() {
    let totalCourses = 0, totalUnits = 0, totalWarnings = 0;

    for (const sem of SEMESTER_ORDER) {
        const container = document.getElementById(`added-${sem}`);
        container.innerHTML = "";

        for (const entry of plan[sem]) {
            const course = COURSES[entry.code];
            const missing = checkPrereqWarnings(sem, entry.code);
            const hasWarning = missing.length > 0;
            if (hasWarning) totalWarnings += missing.length;

            const div = document.createElement("div");
            div.className = `added-course${hasWarning ? " has-warning" : ""}`;

            let html = `<div class="course-info">
                <div class="course-code">MATH ${entry.code}</div>
                <div class="course-name">${course ? course.name : "Unknown"}</div>`;
            if (entry.time && entry.time !== "TBD") {
                html += `<div class="course-time">${entry.days} ${entry.time} — ${entry.instructor}</div>`;
            }
            if (hasWarning) {
                html += `<div class="warning">⚠ Missing prereq: ${missing.map(m => "MATH " + m).join(", ")}</div>`;
            }
            html += `</div><button class="remove-btn" onclick="removeCourse('${sem}','${entry.code}')">&times;</button>`;
            div.innerHTML = html;
            container.appendChild(div);

            totalCourses++;
            if (course) totalUnits += course.units;
        }
    }

    document.getElementById("total-courses").textContent = totalCourses;
    document.getElementById("total-units").textContent = totalUnits;
    document.getElementById("total-warnings").textContent = totalWarnings;

    renderChecklist();
    savePlan();
}

// Semester search dropdowns
function onSemSearch(input) {
    const sem = input.dataset.sem;
    const query = input.value.toLowerCase().trim();
    const dropdown = document.getElementById(`dropdown-${sem}`);
    const available = AVAILABILITY[sem];
    const alreadyAdded = new Set(plan[sem].map(c => c.code));
    const priorCourses = getCoursesBeforeSemester(sem);

    const filtered = available.filter(entry => {
        const course = COURSES[entry.code];
        const searchStr = `${entry.code} ${course ? course.name : ""}`.toLowerCase();
        return query === "" || searchStr.includes(query);
    });

    if (filtered.length === 0) {
        dropdown.classList.remove("open");
        return;
    }

    dropdown.innerHTML = "";
    for (const entry of filtered) {
        const course = COURSES[entry.code];
        const isAdded = alreadyAdded.has(entry.code);
        const missing = course ? course.prereqs.filter(p => !priorCourses.has(p)) : [];

        const div = document.createElement("div");
        div.className = `search-add-option${isAdded ? " disabled" : ""}`;
        if (!isAdded) {
            div.onclick = () => {
                plan[sem].push(entry);
                input.value = "";
                dropdown.classList.remove("open");
                render();
            };
        }

        let html = `<span class="sao-code">MATH ${entry.code}</span> <span class="sao-name">${course ? course.name : ""}</span>`;
        if (entry.time && entry.time !== "TBD") {
            html += `<div class="sao-details">${entry.days} ${entry.time} — ${entry.instructor}</div>`;
        }
        if (missing.length > 0) {
            html += `<div class="sao-warn">⚠ Missing prereq: ${missing.map(m => "MATH " + m).join(", ")}</div>`;
        }
        if (isAdded) {
            html += `<div class="sao-details" style="color:#a29bfe;">Already added</div>`;
        }
        div.innerHTML = html;
        dropdown.appendChild(div);
    }
    dropdown.classList.add("open");
}

// Global lookup
function onLookupInput() {
    const input = document.getElementById("lookup-input");
    const dropdown = document.getElementById("lookup-dropdown");
    const query = input.value.toLowerCase().trim();

    if (query === "") {
        dropdown.classList.remove("open");
        document.getElementById("lookup-result").innerHTML = `<span class="no-result">Select a course to see availability</span>`;
        return;
    }

    const matches = Object.entries(COURSES).filter(([code, c]) => {
        return `${code} ${c.name}`.toLowerCase().includes(query);
    });

    if (matches.length === 0) {
        dropdown.classList.remove("open");
        return;
    }

    dropdown.innerHTML = "";
    for (const [code, course] of matches.slice(0, 10)) {
        const div = document.createElement("div");
        div.className = "lookup-option";
        div.innerHTML = `<span class="lo-code">MATH ${code}</span> <span class="lo-name">${course.name}</span>`;
        div.onclick = () => {
            input.value = `MATH ${code}`;
            dropdown.classList.remove("open");
            showLookupResult(code);
        };
        dropdown.appendChild(div);
    }
    dropdown.classList.add("open");
}

function showLookupResult(code) {
    const result = document.getElementById("lookup-result");
    const course = COURSES[code];
    const availIn = [];
    for (const sem of SEMESTER_ORDER) {
        if (AVAILABILITY[sem].some(e => e.code === code)) {
            availIn.push(sem);
        }
    }

    let html = "";
    if (availIn.length > 0) {
        html += `<span style="color:#aaa;font-size:12px;">Available in:</span> `;
        for (const sem of availIn) {
            const entry = AVAILABILITY[sem].find(e => e.code === code);
            let detail = SEM_NAMES[sem];
            if (entry.time && entry.time !== "TBD") {
                detail += ` (${entry.days} ${entry.time})`;
            }
            html += `<span class="avail-tag ${sem}">${detail}</span> `;
        }
    } else {
        html += `<span class="no-result">Not available in any of the 4 semesters</span>`;
    }
    if (course && course.prereqs.length > 0) {
        html += `<div class="prereq-note">Prerequisites: ${course.prereqs.map(p => "MATH " + p + " (" + (COURSES[p]?.name || "?") + ")").join(", ")}</div>`;
    }
    result.innerHTML = html;
}

function removeCourse(sem, code) {
    plan[sem] = plan[sem].filter(c => c.code !== code);
    render();
}

// Close dropdowns on click outside
document.addEventListener("click", (e) => {
    if (!e.target.closest(".lookup-input-wrap")) {
        document.getElementById("lookup-dropdown").classList.remove("open");
    }
    if (!e.target.closest(".search-add-wrap")) {
        document.querySelectorAll(".search-add-dropdown").forEach(d => d.classList.remove("open"));
    }
});

render();

