// Wishlist
let wishlist = JSON.parse(localStorage.getItem("csula-math-wishlist") || "[]");

function saveWishlist() {
    localStorage.setItem("csula-math-wishlist", JSON.stringify(wishlist));
}

function onWishlistSearch() {
    const input = document.getElementById("wishlist-input");
    const dropdown = document.getElementById("wishlist-dropdown");
    const query = input.value.toLowerCase().trim();

    if (query === "") {
        dropdown.classList.remove("open");
        return;
    }

    const matches = Object.entries(COURSES).filter(([code, c]) => {
        return `${code} ${c.name}`.toLowerCase().includes(query);
    });

    if (matches.length === 0) {
        dropdown.classList.remove("open");
        return;
    }

    dropdown.innerHTML = "";
    for (const [code, course] of matches.slice(0, 10)) {
        const alreadyIn = wishlist.includes(code);
        const div = document.createElement("div");
        div.className = `wl-option${alreadyIn ? " disabled" : ""}`;
        div.innerHTML = `<span style="font-weight:700;">MATH ${code}</span> <span style="color:#aaa;font-size:11px;">${course.name}</span>${alreadyIn ? ' <span style="color:#a29bfe;font-size:10px;">(in wishlist)</span>' : ''}`;
        if (!alreadyIn) {
            div.onclick = () => {
                wishlist.push(code);
                saveWishlist();
                input.value = "";
                dropdown.classList.remove("open");
                renderWishlist();
            };
        }
        dropdown.appendChild(div);
    }
    dropdown.classList.add("open");
}

function removeFromWishlist(code) {
    wishlist = wishlist.filter(c => c !== code);
    saveWishlist();
    renderWishlist();
}

function renderWishlist() {
    const container = document.getElementById("wishlist-items");
    const planned = getAllPlannedCodes();

    if (wishlist.length === 0) {
        container.innerHTML = '<div style="color:#636e72;font-size:12px;text-align:center;padding:10px;">No courses in wishlist yet</div>';
        return;
    }

    container.innerHTML = "";
    for (const code of wishlist) {
        const course = COURSES[code];
        const isScheduled = planned.has(code);
        const sem = findSemesterForCourse(code);

        const div = document.createElement("div");
        div.className = `wishlist-item${isScheduled ? " scheduled" : ""}`;

        let html = "";
        if (isScheduled) {
            html += `<span class="wl-check">&#10003;</span>`;
        } else {
            html += `<span style="color:#636e72;">&#9675;</span>`;
        }
        html += `<span class="wl-code">MATH ${code}</span>`;
        html += `<span class="wl-name">${course ? course.name : "?"}</span>`;
        if (isScheduled && sem) {
            html += `<span class="wl-sem">${sem}</span>`;
        }
        html += `<button class="wl-remove" onclick="removeFromWishlist('${code}')">&times;</button>`;

        div.innerHTML = html;
        container.appendChild(div);
    }
}

// Close dropdowns on click outside
document.addEventListener("click", (e) => {
    if (!e.target.closest(".lookup-input-wrap")) {
        document.getElementById("lookup-dropdown").classList.remove("open");
    }
    if (!e.target.closest(".search-add-wrap")) {
        document.querySelectorAll(".search-add-dropdown").forEach(d => d.classList.remove("open"));
    }
    if (!e.target.closest(".wishlist-add-wrap")) {
        document.getElementById("wishlist-dropdown").classList.remove("open");
    }
});

render();
renderWishlist();

