file.content:
.summary-stats { display: flex; justify-content: center; gap: 30px; font-size: 13px; }
.stat-num { font-weight: 700; font-size: 18px; }
.stat-label { color: #888; font-size: 11px; }
.warnings-count { color: #e17055; }

.wishlist-section {
    background: #16213e;
    border-radius: 12px;
    padding: 24px;
    border: 1px solid #0f3460;
    margin-bottom: 24px;
}
.wishlist-section h3 { color: #a29bfe; margin-bottom: 4px; font-size: 16px; text-align: center; }
.wishlist-subtitle { text-align: center; color: #636e72; font-size: 12px; margin-bottom: 14px; }
.wishlist-add-wrap { position: relative; max-width: 350px; margin: 0 auto 16px; }
.wishlist-input {
    width: 100%;
    padding: 8px 12px;
    border: 1px solid #0f3460;
    border-radius: 6px;
    background: #1a1a2e;
    color: #eee;
    font-size: 13px;
}
.wishlist-input:focus { outline: none; border-color: #a29bfe; }
.wishlist-input::placeholder { color: #555; }
.wishlist-dropdown {
    position: absolute;
    top: 100%;
    left: 0;

