container.innerHTML = "";
for (const code of wishlist) {
    const course = COURSES[code];
    const isScheduled = planned.has(code);
    const sem = findSemesterForCourse(code);

    const div = document.createElement("div");
    div.className = `wishlist-item${isScheduled ? " scheduled" : ""}`;

    let html = "";
    if (isScheduled) {
        html += `<span class="wl-check">&#10003;</span>`;
    } else {
        html += `<span style="color:#636e72;">&#9675;</span>`;
    }
    html += `<span class="wl-code">MATH ${code}</span>`;
    html += `<span class="wl-name">${course ? course.name : "?"}</span>`;
    if (isScheduled && sem) {
        html += `<span class="wl-sem">${sem}</span>`;
    }
    html += `<button class="wl-remove" onclick="removeFromWishlist('${code}')">&times;</button>`;

    div.innerHTML = html;
    container.appendChild(div);
}

input.new_string:
container.innerHTML = "";
for (const code of wishlist) {
    const course = COURSES[code];
    const isScheduled = planned.has(code);
    const sem = findSemesterForCourse(code);

    // Find available semesters
    const availIn = [];
    for (const s of SEMESTER_ORDER) {
        if (AVAILABILITY[s].some(e => e.code === code)) {
            availIn.push(SEM_NAMES[s]);
        }
    }

    const div = document.createElement("div");
    div.className = `wishlist-item${isScheduled ? " scheduled" : ""}`;

    let html = "";
    if (isScheduled) {
        html += `<span class="wl-check">&#10003;</span>`;
    } else {
        html += `<span style="color:#636e72;margin-top:2px;">&#9675;</span>`;
    }
    html += `<div class="wl-info">`;
    html += `<div class="wl-header"><span class="wl-code">MATH ${code}</span> <span class="wl-name">${course ? course.name : "?"}</span></div>`;
    html += `<div class="wl-details">`;
    if (course && course.prereqs.length > 0) {
        html += `<span class="wl-prereqs">Prereqs: ${course.prereqs.map(p => "MATH " + p).join(", ")}</span>`;
    } else {
        html += `<span class="wl-prereqs">Prereqs: None</span>`;
    }
    html += ` · `;
    if (availIn.length > 0) {
        html += `<span class="wl-avail">Available: ${availIn.join(", ")}</span>`;
    } else {
        html += `<span style="color:#e17055;">Not in any semester rotation</span>`;
    }
    if (isScheduled && sem) {
        html += ` · <span class="wl-scheduled-in">Scheduled: ${sem}</span>`;
    }
    html += `</div></div>`;
    html += `<button class="wl-remove" onclick="removeFromWishlist('${code}')">&times;</button>`;

    div.innerHTML = html;
    container.appendChild(div);
}

